// Filtert needs_content Datensaetze die entweder Repair brauchen (ungueltiger Source-Lock
// oder fehlende visualAnchors wenn Bild noetig) und/oder noch kein Summary-Markdown hochgeladen haben.
// FIX: sourceConflict ist laut Fakten-Agent-Spec optional (leerer String bei fehlendem Konflikt) -
// wurde hier absichtlich NICHT als Pflichtfeld gewertet (gleicher Bug wie im QA-Agent, dort am
// 2026-07-19 behoben).
const items = $input.all();

function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; } catch(e) { return {}; }
}
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(s => String(s).trim());
  if (typeof v === 'string' && v.trim()) {
    try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(s => String(s).trim()); } catch(e) {}
  }
  return [];
}
function robustBool(v) {
  if (v === true || v === 1) return true;
  if (typeof v === 'string') { const s = v.trim().toLowerCase(); return s === 'true' || s === '1'; }
  return false;
}

const out = [];
for (const item of items) {
  const j = item.json || {};
  if (safeStr(j.contentStage) !== 'needs_content') continue;

  const analysis = parseObj(j.analysisJson);
  const sl = parseObj(analysis.sourceLock || {});
  const va = parseObj(analysis.visualAnchors || {});
  const slValidFlag = robustBool(analysis.sourceLockValid);
  const vaValidFlag = robustBool(analysis.visualAnchorsValid);

  const slOk = !!(safeStr(sl.sourceTopic) &&
    asArr(sl.requiredTerms).length >= 2 && asArr(sl.requiredObjects).length >= 2 &&
    safeStr(sl.requiredAction) && slValidFlag);
  const vaOk = !!(safeStr(va.satireThemaKonkret) && safeStr(va.satireKonfliktKonkret) &&
    asArr(va.visualPflichtobjekte).length >= 2 && safeStr(va.visualPflichthandlung) &&
    safeStr(va.visualErkennungssatz) && safeStr(va.visualUeberzeichnung) &&
    asArr(va.visualVerboteneErsatzmotive).length >= 2 && vaValidFlag);

  const needsVisual = robustBool(j.visualNeeded) || robustBool(j.instagramSharepicNoetig);
  const repairNeeded = !slOk || (needsVisual && !vaOk);
  const markdownNeeded = !safeStr(j.summaryMarkdownUploadedAt);

  if (!repairNeeded && !markdownNeeded) continue;

  out.push({ json: { ...j, _repairNeeded: repairNeeded, _markdownNeeded: markdownNeeded } });
}
return out;

// Sortierung: 1. firstseen aufsteigend, 2. volfdnr numerisch, 3. vorgangKey lexikografisch
function parseDate(v) {
  if (!v) return 0;
  const t = Date.parse(String(v));
  return Number.isFinite(t) ? t : 0;
}
function parseVolfdnr(v) {
  if (!v) return Infinity;
  const n = parseInt(String(v).replace(/[^0-9]/g, ''), 10);
  return Number.isFinite(n) ? n : Infinity;
}
const items = $input.all();
items.sort((a, b) => {
  const ja = a.json || {}, jb = b.json || {};
  const fa = parseDate(ja.firstseen), fb = parseDate(jb.firstseen);
  if (fa !== fb) return fa - fb;
  const va = parseVolfdnr(ja.volfdnr), vb = parseVolfdnr(jb.volfdnr);
  if (va !== vb) return va - vb;
  return String(ja.vorgangKey || '').localeCompare(String(jb.vorgangKey || ''));
});
return items;

// Stellt die urspruengliche Zeile wieder her (P3b's Rueckgabeform nicht vertrauenswuerdig fuer
// Downstream-Felder wie nextcloudFolder/vorgangKey - gleiches Muster wie die Agent-Restore-Nodes).
const idx = $itemIndex;
const original = $('Filter Abschluss-Kandidaten').itemMatching(idx).json;
return { json: { ...original, _repairAttempted: true } };

const raw = $input.item.json;
const s = Array.isArray(raw) ? (raw[0] || {}) : (raw || {});
const now = new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

let summary = {};
try { summary = JSON.parse(s.summaryJson || '{}'); } catch(e) {}
let analyse = {};
try { analyse = JSON.parse(s.analysisJson || '{}'); } catch(e) {}

function toList(val) {
  if (Array.isArray(val)) return val.map(v => '- ' + v).join('\n');
  if (typeof val === 'string' && val) return val.split(/\s*\|\s*/).map(v => '- ' + v).join('\n');
  return '';
}

// Pfad berechnen
function extractYear(val) {
  const m = String(val || '').match(/\b(20\d{2})\b/);
  return m ? m[1] : new Date().getFullYear().toString();
}
const year = extractYear(s.firstseen || s.lastseen);
let base = (s.nextcloudFolder || '')
  .trim().replace(/\/+$/, '').replace(/\/01_originale$/, '');

let nc_base_path;
if (base.startsWith('/DiePARTEI/Allris/')) {
  nc_base_path = base;
} else if (base) {
  nc_base_path = '/DiePARTEI/Allris/' + year + '/' + base;
} else {
  nc_base_path = '/DiePARTEI/Allris/' + year + '/' + (s.vorgangKey || 'unbekannt').replace(/\//g, '_');
}
nc_base_path = nc_base_path.replace(/\/+/g, '/');
const nc_summary_path = nc_base_path + '/03_zusammenfassung';
const fileName = (s.vorgangKey || 'zusammenfassung').replace(/[\/\s]/g, '_') + '_zusammenfassung.md';


// ── Vorgangskette-Abschnitt (nur bei Folgevorgängen) ────────────────────────
let vorgangsketteMd = '';

if (s.istFolgevorgang === true || String(s.istFolgevorgang || '').trim() === 'true') {
  const details = Array.isArray(s.vorgangsketteDetails) ? s.vorgangsketteDetails : [];
  const fehlend = Array.isArray(s.fehlendeVorherigeVorgaenge) ? s.fehlendeVorherigeVorgaenge : [];
  const vollstaendig = s.vorgangsketteVollstaendig === true;

  const mdLines = [
    '',
    '## Bezug zu vorherigen Vorgängen',
    '',
    `**Stammvorgang:** ${s.stammVorgangsnummer || ''}`,
    `**Vorgangskette vollständig:** ${vollstaendig ? 'Ja' : 'Nein'}`,
    ''
  ];

  const mitKontext    = details.filter(d => d.gefunden && d.kontextVerwendet);
  const ohneKontext   = details.filter(d => d.gefunden && !d.kontextVerwendet);

  if (mitKontext.length > 0) {
    mdLines.push('### Berücksichtigte Vorgänge', '');
    for (const d of mitKontext) {
      const quelleText = d.kontextQuelle === 'summary'
        ? 'vorhandene Zusammenfassung'
        : 'Dokumenttext als Fallback';
      const link = d.allrisUrl ? `[${d.vorgangsnummer}](${d.allrisUrl})` : d.vorgangsnummer;
      mdLines.push(`* ${link} – ${quelleText}`);
    }
    mdLines.push('');
  }

  if (ohneKontext.length > 0) {
    mdLines.push('### Gefunden, aber in diesem Lauf nicht als Kontext verfügbar', '');
    for (const d of ohneKontext) {
      mdLines.push(`* ${d.vorgangsnummer}`);
    }
    mdLines.push('');
  }

  if (fehlend.length > 0) {
    mdLines.push('### Fehlende Vorgänge', '');
    for (const vn of fehlend) {
      mdLines.push(`* ${vn}`);
    }
    mdLines.push('');
  }

  vorgangsketteMd = mdLines.join('\n');
}

const md = [
  '# ' + (s.title || s.vorgangKey || ''),
  '',
  '| | |',
  '|---|---|',
  '| **Vorgangsnummer** | ' + (s.vorgangsnummer || '') + ' |',
  '| **ALLRIS-Link** | ' + (s.allrisUrl || '') + ' |',
  '| **Erstellt** | ' + now + ' |',
  '| **Ampel** | ' + (s.ampel || analyse.ampel || '') + ' |',
  '| **Sprengstoff** | ' + (s.sprengstoff || analyse.sprengstoff || '') + ' |',
  '| **Empfehlung** | ' + (s.empfehlung || analyse.empfehlung || '') + ' |',
  '| **Relevanz** | ' + (s.relevantScore || analyse.relevanz || '') + ' |',
  '',
  '---',
  '',
  ...(vorgangsketteMd ? [vorgangsketteMd, '---', ''] : []),
  '## Zusammenfassung',
  '',
  s.summaryText || summary.summaryText || '',
  '',
  '---',
  '',
  '## Thema',
  '',
  s.thema || summary.thema || '',
  '',
  '## Betroffene',
  '',
  toList(summary.betroffene || s.betroffene),
  '',
  '## Kosten / Haushalt',
  '',
  s.kostenHaushalt || summary.kostenHaushalt || '',
  '',
  '## Bürgerwirkung',
  '',
  s.buergerwirkung || summary.buergerwirkung || '',
  '',
  '## Offene Punkte',
  '',
  toList(summary.offenePunkte),
  '',
  '## Unsicherheiten',
  '',
  toList(summary.unsicherheiten || s.unsicherheitenSummary),
  '',
  '---',
  '',
  '## Bewertung',
  '',
  '**Kurzfassung:** ' + (s.kurzfassung || analyse.kurzfassung || ''),
  '',
  '**Kritische Nachfrage:** ' + (s.kritischeNachfrage || analyse.kritischeNachfrage || ''),
  '',
  '**Begründung:** ' + (s.begruendungBewertung || analyse.begruendungBewertung || ''),
  '',
  '**Wer profitiert:** ' + (s.werProfitiert || analyse.werProfitiert || ''),
  '',
  '**Wer trägt Nachteile:** ' + (s.werZahltOderTraegtNachteile || analyse.werZahltOderTraegtNachteile || ''),
].join('\n');

return { json: { ...s, _mdContent: md, _mdFileName: fileName, nc_summary_path } };

// Nächster Repair-Vorgang (V12_7)
const items = $input.all();
const rawItem = items && items[0];
const j = (rawItem && rawItem.json && typeof rawItem.json === 'object' && !Array.isArray(rawItem.json))
  ? rawItem.json
  : {};
return [{ json: j }];

// Stellt die urspruengliche Zeile wieder her - NC Upload Summary MD (Nextcloud-API-Node) ersetzt
// die Item-Daten durch die Nextcloud-Antwort (kein vorgangKey mehr enthalten), gleiche Bugklasse
// wie in P2 (siehe allris_p2_matrix_context_loss_bug) - Schreibe Markdown-Status braucht vorgangKey.
const idx = $itemIndex;
const original = $('Filter Abschluss-Kandidaten').itemMatching(idx).json;
return { json: { ...original, _markdownUploaded: true } };
